"use client";
import { TimeSlot } from "../../types";
import Button from "../ui/Button";

interface Props {
  slots: TimeSlot[];
  selected: string;
  onSelect: (time: string) => void;
  onBook: () => void;
}

export default function TimeSlots({ slots, selected, onSelect, onBook }: Props) {
  return (
    <div className="glass animate-fade-up-2" style={{ padding: 24 }}>
      <p style={{
        fontSize: 11, fontWeight: 600, color: "#64748b",
        letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 18,
      }}>
        Available Time Slots
      </p>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 8, marginBottom: 20 }}>
        {slots.map(slot => {
          const isSelected = selected === slot.time;
          return (
            <button
              key={slot.time}
              disabled={slot.booked}
              onClick={() => !slot.booked && onSelect(slot.time)}
              style={{
                padding: "9px 6px",
                borderRadius: 8,
                fontSize: 12,
                fontWeight: 500,
                fontFamily: "DM Sans, sans-serif",
                cursor: slot.booked ? "not-allowed" : "pointer",
                border: isSelected
                  ? "1px solid rgba(14,165,233,0.35)"
                  : slot.booked
                  ? "1px solid rgba(148,163,184,0.05)"
                  : "1px solid rgba(148,163,184,0.08)",
                background: isSelected
                  ? "rgba(14,165,233,0.1)"
                  : slot.booked
                  ? "transparent"
                  : "rgba(148,163,184,0.03)",
                color: isSelected
                  ? "#7dd3fc"
                  : slot.booked
                  ? "#1e293b"
                  : "#64748b",
                textDecoration: slot.booked ? "line-through" : "none",
                transition: "all 0.15s",
              }}
              onMouseEnter={e => {
                if (!slot.booked && !isSelected) {
                  e.currentTarget.style.borderColor = "rgba(148,163,184,0.15)";
                  e.currentTarget.style.color = "#94a3b8";
                }
              }}
              onMouseLeave={e => {
                if (!slot.booked && !isSelected) {
                  e.currentTarget.style.borderColor = "rgba(148,163,184,0.08)";
                  e.currentTarget.style.color = "#64748b";
                }
              }}
            >
              {slot.time}
            </button>
          );
        })}
      </div>

      {selected && (
        <div className="animate-scale-in" style={{
          background: "rgba(14,165,233,0.06)",
          border: "1px solid rgba(14,165,233,0.15)",
          borderRadius: 12, padding: "16px 20px",
          display: "flex", alignItems: "center", justifyContent: "space-between",
        }}>
          <div>
            <p style={{ fontSize: 11, color: "#64748b", fontWeight: 600, letterSpacing: 1, textTransform: "uppercase", marginBottom: 3 }}>
              Selected
            </p>
            <p style={{ fontFamily: "Syne, sans-serif", fontWeight: 700, color: "#f1f5f9", fontSize: 18 }}>
              {selected}
            </p>
          </div>
          <Button size="lg" onClick={onBook}>Book Now →</Button>
        </div>
      )}
    </div>
  );
}