import { Doctor } from "../../types";
import { formatCurrency } from "../../lib/utils";
import { TIME_SLOTS } from "../../data/mockData";
import Badge from "../ui/Badge";
import Button from "../ui/Button";
import TimeSlots from "./TimeSlots";

interface Props {
  doctor: Doctor;
  selectedSlot: string;
  onSelectSlot: (time: string) => void;
  onBook: () => void;
  onBack: () => void;
}

export default function DoctorDetail({ doctor, selectedSlot, onSelectSlot, onBook, onBack }: Props) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <Button variant="ghost" size="sm" onClick={onBack}>
        ← Back to Search
      </Button>

      {/* Doctor card */}
      <div className="glass animate-fade-up" style={{ padding: 24 }}>
        <div style={{ display: "flex", gap: 18, alignItems: "flex-start" }}>
          <div style={{
            width: 60, height: 60, borderRadius: 14,
            background: "#0c2340",
            border: "1px solid rgba(14,165,233,0.15)",
            display: "flex", alignItems: "center", justifyContent: "center",
            color: "#7dd3fc", fontWeight: 700, fontSize: 18,
            fontFamily: "Syne, sans-serif", flexShrink: 0,
          }}>
            {doctor.initials}
          </div>
          <div style={{ flex: 1, minWidth: 0 }}>
            <h2 style={{
              fontFamily: "Syne, sans-serif", fontWeight: 700,
              fontSize: 19, color: "#f1f5f9", marginBottom: 8,
            }}>
              {doctor.name}
            </h2>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
              <Badge variant="blue">{doctor.specialization}</Badge>
              <Badge variant="slate">{doctor.hospital}</Badge>
              <Badge variant="green">Available Today</Badge>
            </div>
            <p style={{ color: "#475569", fontSize: 13 }}>
              {doctor.qualifications} · {doctor.experience} · {doctor.languages.join(", ")}
            </p>
          </div>
          <div style={{ textAlign: "right", flexShrink: 0 }}>
            <p style={{ color: "#64748b", fontSize: 11, marginBottom: 4 }}>Consultation Fee</p>
            <p style={{ fontFamily: "Syne, sans-serif", fontWeight: 700, fontSize: 22, color: "#e2e8f0" }}>
              {formatCurrency(doctor.fee)}
            </p>
          </div>
        </div>
      </div>

      {/* Time slots */}
      <TimeSlots
        slots={TIME_SLOTS}
        selected={selectedSlot}
        onSelect={onSelectSlot}
        onBook={onBook}
      />

      {/* Other hospitals */}
      {doctor.otherHospitals.length > 0 && (
        <div className="glass animate-fade-up-3" style={{ padding: 24 }}>
          <p style={{
            fontSize: 11, fontWeight: 600, color: "#64748b",
            letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 16,
          }}>
            Also Available At
          </p>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {doctor.otherHospitals.map(h => (
              <div key={h.name} style={{
                display: "flex", alignItems: "center", justifyContent: "space-between",
                background: "rgba(6,13,26,0.6)", borderRadius: 10,
                padding: "12px 16px", border: "1px solid rgba(148,163,184,0.07)",
              }}>
                <div>
                  <p style={{ fontWeight: 600, color: "#cbd5e1", fontSize: 13 }}>{h.name}</p>
                  <p style={{ color: "#475569", fontSize: 12, marginTop: 2 }}>{h.days} · {h.hours}</p>
                </div>
                <Badge variant="slate">Other Location</Badge>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}