"use client";
import { useState } from "react";
import { Doctor } from "../../types";
import { formatCurrency } from "../../lib/utils";
import Badge from "../ui/Badge";

interface Props {
  doctor: Doctor;
  onChannel: (doctor: Doctor) => void;
}

export default function DoctorCard({ doctor, onChannel }: Props) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      className="glass"
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        padding: "20px 24px",
        display: "flex",
        alignItems: "center",
        gap: 20,
        transition: "all 0.2s",
        borderColor: hovered && doctor.available
          ? "rgba(14,165,233,0.25)"
          : "rgba(148,163,184,0.08)",
        transform: hovered && doctor.available ? "translateY(-1px)" : "none",
        boxShadow: hovered && doctor.available
          ? "0 8px 32px rgba(0,0,0,0.4)"
          : "0 4px 24px rgba(0,0,0,0.3)",
      }}
    >
      {/* Avatar */}
      <div style={{ position: "relative", flexShrink: 0 }}>
        <div style={{
          width: 52, height: 52, borderRadius: 14,
          background: hovered && doctor.available ? "#0369a1" : "#0c2340",
          border: "1px solid rgba(14,165,233,0.15)",
          display: "flex", alignItems: "center", justifyContent: "center",
          color: "#7dd3fc", fontWeight: 700, fontSize: 15,
          fontFamily: "Syne, sans-serif",
          transition: "background 0.3s", flexShrink: 0,
        }}>
          {doctor.initials}
        </div>
        <div style={{
          position: "absolute", bottom: -2, right: -2,
          width: 10, height: 10, borderRadius: "50%",
          background: doctor.available ? "#4ade80" : "#ef4444",
          border: "2px solid #060d1a",
        }} />
      </div>

      {/* Info */}
      <div style={{ flex: 1, minWidth: 0, display: "flex", flexDirection: "column", gap: 7 }}>
        <p style={{
          fontFamily: "Syne, sans-serif", fontWeight: 700,
          color: "#f1f5f9", fontSize: 15,
          overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
        }}>
          {doctor.name}
        </p>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
          <Badge variant="blue">{doctor.specialization}</Badge>
          <Badge variant="slate">{doctor.hospital}</Badge>
        </div>
      </div>

      {/* Right */}
      <div style={{
        display: "flex", flexDirection: "column",
        alignItems: "flex-end", gap: 10, flexShrink: 0,
      }}>
        {/* Fee */}
        <div style={{ textAlign: "right" }}>
          <p style={{
            color: "#475569", fontSize: 10, fontWeight: 500,
            letterSpacing: 1, textTransform: "uppercase", marginBottom: 2,
          }}>
            Consultation
          </p>
          <p style={{ color: "#e2e8f0", fontWeight: 700, fontSize: 15 }}>
            {formatCurrency(doctor.fee)}
          </p>
        </div>

        {/* Channel button */}
        {doctor.available ? (
          <button
            onClick={() => onChannel(doctor)}
            style={{
              padding: "6px 16px",
              borderRadius: 8,
              fontSize: 12,
              fontWeight: 600,
              fontFamily: "DM Sans, sans-serif",
              cursor: "pointer",
              transition: "all 0.2s",
              background: "rgba(3,105,161,0.15)",
              border: "1px solid rgba(14,165,233,0.2)",
              color: "#7dd3fc",
            }}
            onMouseEnter={e => {
              e.currentTarget.style.background = "rgba(3,105,161,0.25)";
              e.currentTarget.style.borderColor = "rgba(14,165,233,0.35)";
            }}
            onMouseLeave={e => {
              e.currentTarget.style.background = "rgba(3,105,161,0.15)";
              e.currentTarget.style.borderColor = "rgba(14,165,233,0.2)";
            }}
          >
            Channel
          </button>
        ) : (
          <div style={{
            padding: "5px 12px", borderRadius: 99,
            fontSize: 11, fontWeight: 500,
            background: "rgba(148,163,184,0.05)",
            border: "1px solid rgba(148,163,184,0.1)",
            color: "#334155",
          }}>
            Fully Booked
          </div>
        )}
      </div>
    </div>
  );
}